examples.before_code:
library ieee;
  use ieee.std_logic_1164.all;
  use ieee.numeric_std.all;
  use work.cpu_defs_pkg.all;

entity ex_mem_reg is
  port (
    clk   : in    std_logic;
    rst   : in    std_logic;
    stall : in    std_logic;
    flush : in    std_logic;

    -- CONTROL inputs (from EX)
    return_reset_in          : in    std_logic;
    mem_to_pc_enable_in      : in    std_logic;
    wb_reg_source_in         : in    wb_src_t;
    mem_read_enable_in       : in    std_logic;
    mem_write_enable_in      : in    std_logic;
    write_back_enable_in     : in    std_logic;
    sp_bit_in                : in    std_logic;
    mem_write_data_select_in : in    mem_write_data_src_t;
    -- destination register/address
    write_addr_in : in    std_logic_vector(2 downto 0);

    -- DATA inputs (from EX)
    pc_in_plus_2_in : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    alu_result_in   : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    reg_data_2_in   : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    ccr_flags_in    : in    std_logic_vector(2 downto 0);

    -- OUTPUTS to MEM stage
    return_reset_out          : out   std_logic;
    mem_to_pc_enable_out      : out   std_logic;
    wb_reg_source_out         : out   wb_src_t;
    mem_read_enable_out       : out   std_logic;
    mem_write_enable_out      : out   std_logic;
    write_back_enable_out     : out   std_logic;
    sp_bit_out                : out   std_logic;
    mem_write_data_select_out : out   mem_write_data_src_t;
    -- destination register/address
    write_addr_out : out   std_logic_vector(2 downto 0);

    pc_out_plus_2  : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    alu_result_out : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    reg_data_2_out : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    ccr_flags_out  : out   std_logic_vector(2 downto 0)
  );
end entity ex_mem_reg;

architecture behavioral of ex_mem_reg is

begin

  process (clk) is
  begin

    if rising_edge(clk) then
      if (rst = '1'  or flush = '1') then
        -- insert NOPs
        mem_read_enable_out       <= '0';
        mem_write_enable_out      <= '0';
        write_back_enable_out     <= '0';
        mem_to_pc_enable_out      <= '0';
        wb_reg_source_out         <= "00";
        mem_write_data_select_out <= (others => '0');
        sp_bit_out                <= '0';
        write_addr_out            <= (others => '0');
        pc_out_plus_2             <= (others => '0');
        alu_result_out            <= (others => '0');
        reg_data_2_out            <= (others => '0');
        ccr_flags_out             <= (others => '0');
        return_reset_out          <= '0';
      elsif (stall = '1') then
        null; -- hold
      else
        mem_read_enable_out       <= mem_read_enable_in;
        mem_write_enable_out      <= mem_write_enable_in;
        write_back_enable_out     <= write_back_enable_in;
        mem_to_pc_enable_out      <= mem_to_pc_enable_in;
        wb_reg_source_out         <= wb_reg_source_in;
        mem_write_data_select_out <= mem_write_data_select_in;
        sp_bit_out                <= sp_bit_in;
        write_addr_out            <= write_addr_in;
        pc_out_plus_2             <= pc_in_plus_2_in;
        alu_result_out            <= alu_result_in;
        reg_data_2_out            <= reg_data_2_in;
        ccr_flags_out             <= ccr_flags_in;
        return_reset_out          <= return_reset_in;
      end if;
    end if;

  end process;

end architecture behavioral;

