architecture behavioral of id_ex_reg is

begin

  process (clk) is
  begin

    if rising_edge(clk) then
      if (rst = '1' or flush = '1') then
        -- insert NOPs / safe defaults on flush
        return_reset_out          <= '0';
        mem_to_pc_enable_out      <= '0';
        wb_reg_source_out         <= "00";
        mem_read_enable_out       <= '0';
        mem_write_enable_out      <= '0';
        write_back_enable_out     <= '0';
        imm_bit_out               <= '0';
        push_pop_select_out       <= '0';
        jmp_type_out              <= "00";
        mem_write_data_select_out <= "00";
        sp_bit_out                <= '0';
        ccr_selector_out          <= "00";
        ccr_enable_out            <= '0';
        set_c_out                 <= '0';
        is_branch_out             <= '0';
        pc_out_plus_1             <= (others => '0');
        reg_data_1_out            <= (others => '0');
        reg_data_2_out            <= (others => '0');
        read_addr_1_out           <= (others => '0');
        read_addr_2_out           <= (others => '0');
        write_addr_out            <= (others => '0');
        alu_op_out                <= alu_pas;
        is_input_instruction_out  <= '0';
        output_instruction_en_out <= '0';
      elsif (stall = '1') then
        -- hold outputs (do nothing)
        null;
      else
        -- normal capture
        return_reset_out          <= return_reset_in;
        mem_to_pc_enable_out      <= mem_to_pc_enable_in;
        wb_reg_source_out         <= wb_reg_source_in;
