library ieee;
  use ieee.std_logic_1164.all;
  use ieee.numeric_std.all;
  use work.cpu_defs_pkg.all;

entity alu is
  generic (
    data_width : integer := DATA_WIDTH
  );
  port (
    src_a   : in    std_logic_vector(data_width - 1 downto 0);
    src_b   : in    std_logic_vector(data_width - 1 downto 0);
    alu_sel : in    std_logic_vector(2 downto 0);

    result : out   std_logic_vector(data_width - 1 downto 0);
    flags  : out   std_logic_vector(2 downto 0)
  );
end entity alu;

architecture behavioral of alu is

  -- Internal signals with 1 extra bit for Carry detection
  signal temp_result : unsigned(data_width downto 0);
  signal a_uns       : unsigned(data_width - 1 downto 0);
  signal b_uns       : unsigned(data_width - 1 downto 0);

begin

  a_uns <= unsigned(src_a);
  b_uns <= unsigned(src_b);

  process (src_a, src_b, alu_sel, a_uns, b_uns, temp_result) is
  begin

    temp_result <= (others => '0');

    case alu_sel is

      when "000" =>                                   -- ADD

        temp_result <= ('0' & a_uns) + ('0' & b_uns);

      when "001" =>                                   -- SUB

        temp_result <= ('0' & a_uns) - ('0' & b_uns);

      when "010" =>                                   -- INC

        temp_result <= ('0' & a_uns) + 1;

      when "011" =>                                   -- DEC

        temp_result <= ('0' & a_uns) - 1;

      when "100" =>                                   -- NOT (One's Comp)

        temp_result <= '0' & (not a_uns);

      when "101" =>                                   -- PASS

        temp_result <= '0' & a_uns;

      when "110" =>                                   -- AND

        temp_result <= '0' & (a_uns and b_uns);

      when others =>                                  -- Unused "111"

        temp_result <= (others => '0');

    end case;

  end process;

  result <= std_logic_vector(temp_result(data_width - 1 downto 0));

  flags(ccr_carry_bit_pos) <= temp_result(data_width);

  flags(ccr_negative_bit_pos) <= temp_result(data_width - 1);

  flags(ccr_zero_bit_pos) <= '1' when temp_result(data_width - 1 downto 0) = 0 else
                             '0';

end architecture behavioral;

