library ieee;
  use ieee.std_logic_1164.all;
  use ieee.numeric_std.all;
  use work.cpu_defs_pkg.all;

entity control_unit is
  port (
    clk         : in    std_logic;
    rst         : in    std_logic;
    intr        : in    std_logic; -- Int Signal
    stall_fetch : out   std_logic; -- To freeze PC/IF-ID during multi-cycle ops

    opcode : in    opcode_t;

    -- Execute stage controls
    alu_op        : out   alu_op_t;
    alu_src_b_imm : out   std_logic;        -- 0: Reg2, 1: Immediate
    ccr_write_en  : out   std_logic;        -- Update Flags?
    ccr_src_sel   : out   ccr_src_select_t; -- ALU flags vs Mem vs SetC

    -- Memory stage control
    mem_read     : out   std_logic;
    mem_write    : out   std_logic;
    sp_enable    : out   std_logic;            -- 0: Normal Mem, 1: Stack Access
    push_pop     : out   push_pop_t;           -- 0: Push, 1: Pop
    mem_data_src : out   mem_write_data_src_t; -- What data to write to memory?

    -- Writeback stage control
    reg_write_en  : out   std_logic; -- Write to Register File?
    reg_write_sel : out   std_logic; -- -- rdst always 26:24 from assembler, but this is needed for swap. 0: rdst, 1: rsrc2
    wb_source     : out   wb_src_t;  -- ALU vs Mem vs InPort
    ccr_enable    : out   std_logic; -- for RTI (reads ccr from memory), this never happens with ccr from alu because RTI flushes 3 stages

    -- control flow/branching
    jmp_type       : out   jmp_t;     --  unconditional, JZ, JN, JC
    is_branch      : out   std_logic; -- needed in execute to know if branch instruction
    is_call_signal : out   std_logic; -- Helper for Call logic (if needed)
    is_ret_signal  : out   std_logic; -- for ret and rti (when pc mux sees this from mem stage, it knows to take from data bus)

    -- Immediate
    is_immediate_instr : out   std_logic; -- propagates till ex/mem, hazard detection unit uses it to flush the if/id reg

    -- I/O
    is_out_port : out   std_logic;
    is_in_port  : out   std_logic
  );
end entity control_unit;

architecture behavioral of control_unit is

  type state_t is (
    s_fetch,           -- normal operation
    s_swap_2,          -- Swap Cycle 2
    s_int_push_pc,     -- Interrupt Cycle 1
    s_int_push_ccr,    -- Interrupt Cycle 2
    s_int_load_vector, -- Interrupt Cycle 3
    s_rti_pop_pc       -- RTI Cycle 2
  );

  signal current_state, next_state : state_t;

begin

  process (clk, rst) is
  begin

    if (rst = '1') then
      current_state <= s_fetch;
    elsif rising_edge(clk) then
      current_state <= next_state;
    end if;

  end process;

  process (current_state, opcode, intr) is
  begin

    -- defaults
    next_state  <= current_state;
    stall_fetch <= '0';                                  -- Default: Don't stall

    alu_op        <= alu_pas_a;                          -- can be anything
    alu_src_b_imm <= '0';                                -- default to reg2
    ccr_write_en  <= '0';
    ccr_src_sel   <= ccr_from_alu_flags;

    mem_read     <= '0';
    mem_write    <= '0';
    sp_enable    <= '0';
    push_pop     <= push_op;                             -- don't care since sp_enable is 0
    mem_data_src <= mem_data_read_data_2;                -- rsrc2 by default, won't matter since reg_write_en is 0

    reg_write_en  <= '0';
    reg_write_sel <= '0';                                -- Default to Rdst
    wb_source     <= wb_from_alu;
    ccr_enable    <= '0';

    jmp_type           <= jmp_always;                    -- unconditional (is_branch = 0)
    is_branch          <= '0';
    is_call_signal     <= '0';
    is_ret_signal      <= '0';
    is_immediate_instr <= '0';

    is_out_port <= '0';
    is_in_port  <= '0';

    case current_state is

      when s_fetch =>

        -- Hardware Interrupt
        if (intr = '1') then
          stall_fetch <= '1';
          next_state  <= s_int_push_pc;                  -- same sequence as int instruction
        else

          case opcode is

            -- ALU(reg) 00
            -- ccr from alu is default already
            when op_add =>

              alu_op       <= alu_add;
              reg_write_en <= '1';
              ccr_write_en <= '1';

            when op_sub =>

              alu_op       <= alu_sub;
              reg_write_en <= '1';
              ccr_write_en <= '1';

            when op_and =>

              alu_op       <= alu_and;
              reg_write_en <= '1';
              ccr_write_en <= '1';

            when op_not =>

              alu_op       <= alu_not;
              reg_write_en <= '1';
              ccr_write_en <= '1';

            when op_inc =>

              alu_op       <= alu_inc;
              reg_write_en <= '1';
              ccr_write_en <= '1';

            when op_mov =>

              alu_op       <= alu_pas_a;                 -- Pass Src1 or 2?
              reg_write_en <= '1';

            when op_setc =>

              ccr_write_en <= '1';
              ccr_src_sel  <= ccr_from_set_c;

            when op_swap =>

              -- Cycle 1: Read Rsrc (Val B), Write to Rdst
              alu_op        <= alu_pas_b;
              reg_write_en  <= '1';
              reg_write_sel <= '0';                      -- Target Rdst

              stall_fetch <= '1';                        -- Freeze pipeline
              next_state  <= s_swap_2;

            -- IMM/sys - "01"
            when op_nop =>

            -- (Defaults are 0)

            when op_hlt =>

            -- Handled by Hazard Unit mainly (Freeze PC), no control signals needed here

            when op_out =>

              is_out_port <= '1';
              alu_op      <= alu_pas_a;                  -- assuming not sure

            when op_in =>

              is_in_port   <= '1';
              reg_write_en <= '1';
              wb_source    <= wb_from_in_port;

            when op_iadd =>

              alu_op             <= alu_add;
              alu_src_b_imm      <= '1';
              reg_write_en       <= '1';
              ccr_write_en       <= '1';
              is_immediate_instr <= '1';

            when op_ldm =>

              alu_op             <= alu_pas_b;
              alu_src_b_imm      <= '1';
              reg_write_en       <= '1';
              is_immediate_instr <= '1';

            -- Memory - "10"
            when op_ldd =>

              alu_op             <= alu_add;             -- calculate addr (reg1 + Imm)
              alu_src_b_imm      <= '1';
              mem_read           <= '1';
              reg_write_en       <= '1';
              wb_source          <= wb_from_mem;
              is_immediate_instr <= '1';                 -- LDD has offset (Imm)

            when op_std =>

              alu_op             <= alu_add;             -- calculate addr
              alu_src_b_imm      <= '1';
              mem_write          <= '1';
              is_immediate_instr <= '1';                 -- STD has offset (Imm)

            when op_push =>

              sp_enable    <= '1';                       -- Use SP Logic
              push_pop     <= push_op;                   -- Decrement SP
              mem_write    <= '1';
              mem_data_src <= mem_data_read_data_2;      -- Push Register Value -- why do we have it reg2 not 1?
              alu_op       <= alu_pas_a;                 -- Pass Rdst to memory stage logic

            when op_pop =>

              sp_enable    <= '1';                       -- Use SP Logic -- input to memory address mux, and a mux decode which sp goes to the mempry address using push_pop
              push_pop     <= pop_op;                    -- Increment SP
              mem_read     <= '1';
              reg_write_en <= '1';
              wb_source    <= wb_from_mem;

            -- Branch/Control "11"
            when op_jz =>

              is_branch          <= '1';
              jmp_type           <= jmp_jz;
              is_immediate_instr <= '1';                 -- Target is Imm

            when op_jn =>

              is_branch          <= '1';
              jmp_type           <= jmp_jn;
              is_immediate_instr <= '1';

            when op_jc =>

              is_branch          <= '1';
              jmp_type           <= jmp_jc;
              is_immediate_instr <= '1';

            when op_jmp =>

              is_branch          <= '1';
              jmp_type           <= jmp_always;          -- Unconditional
              is_immediate_instr <= '1';

            when op_call =>

              is_branch          <= '1';                 -- It is a jump
              is_call_signal     <= '1';
              jmp_type           <= jmp_always;
              is_immediate_instr <= '1';
              -- Call also needs to PUSH PC+2.
              mem_write    <= '1';                       -- Write to Stack
              sp_enable    <= '1';                       -- Stack Op
              push_pop     <= push_op;                   -- Push
              mem_data_src <= mem_data_pc_plus_2;        -- Push Return Addr

            when op_ret =>

              is_ret_signal <= '1';
              is_branch     <= '1';                      -- Technically a branch to LR
              jmp_type      <= jmp_always;
              -- RET is a POP PC
              mem_read  <= '1';
              sp_enable <= '1';
              push_pop  <= pop_op;
              wb_source <= wb_from_mem;                  -- Value goes to PC (handled in Datapath)

            when op_int =>

              -- Software Interrupt Trigger
              stall_fetch <= '1';
              next_state  <= s_int_push_pc;

            when op_rti =>

              -- Cycle 1: Pop CCR
              mem_read   <= '1';
              sp_enable  <= '1';
              push_pop   <= pop_op;
              ccr_enable <= '1';                         -- Read CCR from Mem

              stall_fetch <= '1';
              next_state  <= s_rti_pop_pc;

            when others =>

          -- Unknown Opcode

          end case;

        end if;                                          -- End Intr/Opcode check

      -- : SWAP CYCLE 2
      when s_swap_2 =>

        -- Read Rdst (in A), Write to Rsrc
        alu_op        <= alu_pas_a;
        reg_write_en  <= '1';
        reg_write_sel <= '1';                            -- Force write to Rsrc (23:21)

        stall_fetch <= '0';                              -- Unfreeze
        next_state  <= s_fetch;

      -- INT CYCLE 1 (PUSH PC)
      when s_int_push_pc =>

        mem_write    <= '1';
        sp_enable    <= '1';
        push_pop     <= push_op;
        mem_data_src <= mem_data_pc_plus_2;              -- Push PC

        stall_fetch <= '1';
        next_state  <= s_int_push_ccr;

      -- STATE: INT CYCLE 2 (PUSH CCR)
      when s_int_push_ccr =>

        mem_write    <= '1';
        sp_enable    <= '1';
        push_pop     <= push_op;
        mem_data_src <= mem_data_ccr_flags;              -- Push Flags

        stall_fetch <= '1';
        next_state  <= s_int_load_vector;

      -- STATE: INT CYCLE 3 (LOAD VECTOR)
      when s_int_load_vector =>

        mem_read  <= '1';
        wb_source <= wb_from_mem;                        -- To PC

        is_branch <= '1';
        jmp_type  <= jmp_always;

        stall_fetch <= '0';                              -- Unfreeze
        next_state  <= s_fetch;

      -- STATE: RTI CYCLE 2 (POP PC)
      when s_rti_pop_pc =>

        mem_read  <= '1';
        sp_enable <= '1';
        push_pop  <= pop_op;
        wb_source <= wb_from_mem;                        -- To PC (takes from bus since jmp_always damn)

        is_ret_signal <= '1';
        is_branch     <= '1';
        jmp_type      <= jmp_always;

        stall_fetch <= '0';                              -- Unfreeze
        next_state  <= s_fetch;

    end case;

  end process;

end architecture behavioral;

