entity priority_pc_mux is
  port (
    rst                    : in  std_logic;  -- async reset (highest priority)
    mem_to_pc_enable       : in  std_logic;  -- choose mem_pc when 1
    stall                  : in  std_logic;  -- hold current PC when 1
    jump_take              : in  std_logic;  -- choose jump_pc when 1
    mem_pc                 : in  std_logic_vector(DATA_WIDTH - 1 downto 0);
    jump_pc                : in  std_logic_vector(DATA_WIDTH - 1 downto 0);
    current_pc             : in  std_logic_vector(DATA_WIDTH - 1 downto 0);
    pc_plus_1              : in  std_logic_vector(DATA_WIDTH - 1 downto 0);

    pc_next                : out std_logic_vector(DATA_WIDTH - 1 downto 0)
  );
end entity priority_pc_mux;

architecture rtl of priority_pc_mux is
begin
  -- Combinational priority chooser
  p_select : process (rst, mem_to_pc_enable, mem_pc, jump_take, jump_pc, stall, current_pc, pc_plus_1)
  begin
    if (rst = '1') then
      pc_next <= (others => '0');                         -- Priority 1: reset
    elsif (mem_to_pc_enable = '1') then
      pc_next <= mem_pc;                                  -- Priority 2: memory (RET/RTI/INT)
    elsif (jump_take = '1') then
      pc_next <= jump_pc;                                 -- Priority 3: jump
    elsif (stall = '1') then
      pc_next <= current_pc;                              -- Priority 4: stall/HLT -> hold PC
    else
      pc_next <= pc_plus_1;                               -- Priority 5: PC + 1
    end if;
  end process p_select;

end architecture rtl;

