library ieee;
  use ieee.std_logic_1164.all;
  use ieee.numeric_std.all;
  use work.cpu_defs_pkg.all;

entity execute_stage is
  port (
    clk : in    std_logic;
    rst : in    std_logic;
    -- signals inputs
    alu_op       : in    alu_op_t;
    jmp_type     : in    jmp_t;
    ccr_selector : in    ccr_src_select_t;
    ccr_enable   : in    std_logic;
    set_c        : in    std_logic;
    is_branch    : in    std_logic;
    -- data inputs
    pc_in_plus_1         : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    reg_data_1           : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    reg_data_2_in        : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    imm_data             : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    alu_out_from_mem     : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    write_back_data_in   : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    ccr_flags_in         : in    std_logic_vector(2 downto 0);
    mux_1_alu_src_select : in    std_logic_vector(1 downto 0);
    mux_2_alu_src_select : in    std_logic_vector(1 downto 0);
    in_port_data_in      : in    std_logic_vector(DATA_WIDTH - 1 downto 0);

    -- signal outputs
    jmp_taken : out   std_logic;
    -- data outputs
    pc_out_plus_2     : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    alu_result        : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    reg_data_2_out    : out   std_logic_vector(DATA_WIDTH - 1 downto 0);
    ccr_flags_out     : out   std_logic_vector(2 downto 0);
    out_port_data_out : out   std_logic_vector(DATA_WIDTH - 1 downto 0)
  );
end entity execute_stage;

architecture behavioral of execute_stage is

  -- Internal signals
  signal alu_src_a    : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal alu_src_b    : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal alu_flags    : std_logic_vector(2 downto 0);
  signal ccr_register : std_logic_vector(2 downto 0); -- The stored Architectural Register
  signal ccr_next_val : std_logic_vector(2 downto 0); -- The value we WANT to write next

begin

  -- MUX 1 for ALU source A
  alu_src_a <= in_port_data_in when mux_1_alu_src_select = "00" else
               alu_out_from_mem when mux_1_alu_src_select = "01" else
               write_back_data_in when mux_1_alu_src_select = "10" else
               reg_data_1 when mux_1_alu_src_select = "11";

  -- MUX 2 for ALU source B
  alu_src_b <= imm_data when mux_2_alu_src_select = "00" else
               alu_out_from_mem when mux_2_alu_src_select = "01" else
               write_back_data_in when mux_2_alu_src_select = "10" else
               reg_data_2_in when mux_2_alu_src_select = "11";

  -- ccr update logic
  process (all) is
  begin

    case ccr_selector is

      when "00" =>

        ccr_next_val <= alu_flags;

      when "01" =>

        ccr_next_val <= ccr_flags_in;

      when "10" =>                                                                -- SETC (Set Carry)

        -- "Forces Carry to 1, preserving Zero and Negative"
        ccr_next_val                    <= ccr_register;
        ccr_next_val(ccr_carry_bit_pos) <= '1';

      when others =>

        ccr_next_val <= ccr_register;                                             -- Maintain current value

    end case;

  end process;

  process (clk, rst) is
  begin

