architecture fetch_stage_arch of fetch_stage is

  -- Internal signals
  signal jump_take    : std_logic;
  signal pc_reg       : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');
  signal pc_plus_1_s  : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal pc_next      : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal reset_active : std_logic := '1'; -- Track if we're in reset sequence

begin

  -- Compute pc + 1
  pc_plus_1_s <= std_logic_vector(unsigned(pc_reg) + 1);

  jump_take <= jump_taken_from_execute or jump_taken_from_decode;

  u_prio : entity work.priority_pc_mux
    port map (
      rst              => rst,
      mem_to_pc_enable => mem_to_pc_enable_in,
      stall            => stall,
      jump_take        => jump_take,
      mem_pc           => mem_data_in,
      jump_pc          => jump_pc_in,
      current_pc       => pc_reg,
      pc_plus_1        => pc_plus_1_s,
      pc_next          => pc_next
    );

  -- PC register process with reset vector loading
  -- Reset sequence:
  --   1. During rst='1': pc_reg=0, pc_out=0 -> memory reads M[0] (reset vector)
  --   2. First clock after rst='0': load mem_data_in (reset vector from M[0]) into pc_reg
  --   3. Normal operation continues
  process (clk, rst) is
  begin

    if (rst = '1') then
      pc_reg       <= (others => '0'); -- async reset to zero, so pc_out=0 reads M[0]
