    mem_write_data_select_in : in    mem_write_data_src_t;

    -- DATA inputs (from EX/MEM register)
    alu_result_in : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    pc_plus_2_in  : in    std_logic_vector(DATA_WIDTH - 1 downto 0);
    ccr_flags_in  : in    std_logic_vector(2 downto 0);
    reg_data_2_in : in    std_logic_vector(DATA_WIDTH - 1 downto 0);

    -- MEMORY interface (directly to RAM)
    mem_address    : out   std_logic_vector(ADDR_WIDTH - 1 downto 0);
    mem_write_data : out   std_logic_vector(DATA_WIDTH - 1 downto 0)
  );
end entity memory_stage;

architecture behavioral of memory_stage is

  signal sp_reg              : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal sp_plus_1           : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal stack_address       : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal effective_address   : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal selected_write_data : std_logic_vector(DATA_WIDTH - 1 downto 0);

begin

  -- SP+1 for POP operations (read from SP+1, then increment)
  sp_plus_1 <= std_logic_vector(unsigned(sp_reg) + 1);

  -- PUSH uses SP (write at SP, then decrement)
  -- POP uses SP+1 (read from SP+1, then increment)
  stack_address <= sp_reg when push_pop_select_in = push_op else sp_plus_1;

  process (clk, rst) is
  begin

    if (rst = '1') then
      sp_reg <= sp_init;
    elsif rising_edge(clk) then
      if (sp_bit_in = '1') then
        if (push_pop_select_in = push_op) then
          sp_reg <= std_logic_vector(unsigned(sp_reg) - 1);
        else
          sp_reg <= std_logic_vector(unsigned(sp_reg) + 1);
        end if;
      end if;
    end if;

  end process;

  with sp_bit_in select effective_address <=
    stack_address when '1',
    alu_result_in when others;

  mem_address <= effective_address(ADDR_WIDTH - 1 downto 0);

  with mem_write_data_select_in select selected_write_data <=
    alu_result_in when mem_data_alu,
    pc_plus_2_in when mem_data_pc_plus_2,
    reg_data_2_in when mem_data_reg_data_2,
    (x"0000000" & "0" & ccr_flags_in) when mem_data_ccr_flags,
    (others => '0') when others;

  mem_write_data <= selected_write_data;

end architecture behavioral;

