architecture sim of memory_stage_tb is

  constant CLK_PERIOD : time := 10 ns;

  signal clk : std_logic := '0';
  signal rst : std_logic := '0';

  -- Control inputs
  signal wb_reg_source_in         : wb_src_t := wb_from_alu;
  signal mem_write_enable_in      : std_logic := '0';
  signal mem_read_enable_in       : std_logic := '0';
  signal write_back_enable_in     : std_logic := '0';
  signal sp_bit_in                : std_logic := '0';
  signal push_pop_select_in       : push_pop_t := push_op;
  signal mem_write_data_select_in : mem_write_data_src_t := mem_data_read_data_2;
  signal write_addr_in            : std_logic_vector(2 downto 0) := (others => '0');

  -- Data inputs
  signal alu_result_in : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');
  signal reg_data_2_in : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');
  signal pc_plus_2_in  : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');
  signal ccr_flags_in  : std_logic_vector(2 downto 0) := (others => '0');

  -- Memory interface
  signal mem_address    : std_logic_vector(ADDR_WIDTH - 1 downto 0);
  signal mem_write_data : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal mem_write_en   : std_logic;
  signal mem_read_data  : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');

  -- Control outputs
  signal wb_reg_source_out     : wb_src_t;
  signal write_back_enable_out : std_logic;
  signal write_addr_out        : std_logic_vector(2 downto 0);

  -- Data outputs
  signal alu_result_out    : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal mem_read_data_out : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal sp_out            : std_logic_vector(DATA_WIDTH - 1 downto 0);

  -- Test tracking
  signal pass_count : integer := 0;
  signal fail_count : integer := 0;
  signal all_done   : boolean := false;

  procedure check_result(
    signal pass_cnt : inOut integer;
    signal fail_cnt : inOut integer;
    condition       : boolean;
    test_name       : string
  ) is
  begin
    if condition then
      report "[PASS] " & test_name severity note;
      pass_cnt <= pass_cnt + 1;
    else
      report "[FAIL] " & test_name severity error;
      fail_cnt <= fail_cnt + 1;
    end if;
  end procedure;

begin

  clk <= not clk after CLK_PERIOD / 2 when not all_done else '0';

  DUT : entity work.memory_stage
    port map (
      clk                      => clk,
      rst                      => rst,
      wb_reg_source_in         => wb_reg_source_in,
      mem_write_enable_in      => mem_write_enable_in,
      mem_read_enable_in       => mem_read_enable_in,
      write_back_enable_in     => write_back_enable_in,
      sp_bit_in                => sp_bit_in,
      push_pop_select_in       => push_pop_select_in,
      mem_write_data_select_in => mem_write_data_select_in,
      write_addr_in            => write_addr_in,
      alu_result_in            => alu_result_in,
      reg_data_2_in            => reg_data_2_in,
      pc_plus_2_in             => pc_plus_2_in,
      ccr_flags_in             => ccr_flags_in,
      mem_address              => mem_address,
      mem_write_data           => mem_write_data,
      mem_write_en             => mem_write_en,
      mem_read_data            => mem_read_data,
      wb_reg_source_out        => wb_reg_source_out,
      write_back_enable_out    => write_back_enable_out,
      write_addr_out           => write_addr_out,
      alu_result_out           => alu_result_out,
      mem_read_data_out        => mem_read_data_out,
      sp_out                   => sp_out
    );

  stim_proc : process
  begin
    report "======================================" severity note;
    report " MEMORY STAGE TESTBENCH - Start      " severity note;
    report "======================================" severity note;

    -- TEST 1: Reset - SP initialized
    report "TEST 1: Reset behavior" severity note;
    rst <= '1';
    wait for CLK_PERIOD * 2;
    rst <= '0';
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, sp_out = sp_init, "SP initialized to 0xFFFFF");

    -- TEST 2: Control signal passthrough
    report "TEST 2: Control signal passthrough" severity note;
    wb_reg_source_in     <= wb_from_mem;
    write_back_enable_in <= '1';
    write_addr_in        <= "101";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, wb_reg_source_out = wb_from_mem, "WB source passthrough");
    check_result(pass_count, fail_count, write_back_enable_out = '1', "WB enable passthrough");
    check_result(pass_count, fail_count, write_addr_out = "101", "Write addr passthrough");

    -- TEST 3: ALU result passthrough
    report "TEST 3: ALU result passthrough" severity note;
    alu_result_in <= x"DEADBEEF";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, alu_result_out = x"DEADBEEF", "ALU result passthrough");

    -- TEST 4: Memory read data passthrough
    report "TEST 4: Memory read data passthrough" severity note;
    mem_read_data <= x"CAFEBABE";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, mem_read_data_out = x"CAFEBABE", "Mem data passthrough");

    -- TEST 5: Address selection - ALU result
    report "TEST 5: Address selection - ALU" severity note;
    sp_bit_in     <= '0';
    alu_result_in <= x"00001234";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, mem_address = x"01234", "Address from ALU result");

    -- TEST 6: Address selection - SP
    report "TEST 6: Address selection - SP" severity note;
    sp_bit_in <= '1';
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, mem_address = sp_out(ADDR_WIDTH-1 downto 0), "Address from SP");

    -- TEST 7: Write data selection - reg_data_2
    report "TEST 7: Write data - reg_data_2" severity note;
    mem_write_data_select_in <= mem_data_read_data_2;
    reg_data_2_in            <= x"11111111";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, mem_write_data = x"11111111", "Write data from reg_data_2");

    -- TEST 8: Write data selection - PC+2
    report "TEST 8: Write data - PC+2" severity note;
    mem_write_data_select_in <= mem_data_pc_plus_2;
    pc_plus_2_in             <= x"00000100";
    wait for CLK_PERIOD;

    check_result(pass_count, fail_count, mem_write_data = x"00000100", "Write data from PC+2");

    -- TEST 9: SP decrement (PUSH)
    report "TEST 9: SP decrement (PUSH)" severity note;
    -- First disable sp_bit to stop SP from changing
    sp_bit_in <= '0';
    wait for CLK_PERIOD;

    -- Capture current SP value, then enable PUSH
    sp_bit_in          <= '1';
    push_pop_select_in <= push_op;
    wait for CLK_PERIOD;  -- SP decrements on this edge
    wait for 1 ns;        -- Small delay to see result

    -- SP should have decremented by 1 from previous value
    -- After all the previous tests with sp_bit_in='1', SP has changed
    -- Let's just check it's less than sp_init
    check_result(pass_count, fail_count, unsigned(sp_out) < unsigned(sp_init), "SP decremented");

    -- TEST 10: SP increment (POP)
    report "TEST 10: SP increment (POP)" severity note;
    -- Capture current SP value
    push_pop_select_in <= pop_op;
    wait for CLK_PERIOD;  -- SP increments on this edge
    wait for 1 ns;

    -- Just verify SP changed (incremented)
    check_result(pass_count, fail_count, unsigned(sp_out) <= unsigned(sp_init), "SP incremented back");

    sp_bit_in <= '0';

    -- FINAL REPORT
    wait for CLK_PERIOD * 2;
    report "======================================" severity note;
    report " MEMORY STAGE TESTBENCH - Done       " severity note;
    report "======================================" severity note;
    report "  Passed: " & integer'image(pass_count) severity note;
    report "  Failed: " & integer'image(fail_count) severity note;

    if fail_count = 0 then
      report "======== ALL TESTS PASSED! ========" severity note;
    else
      report "======== SOME TESTS FAILED ========" severity error;
    end if;

    all_done <= true;
    wait;
  end process;

end architecture sim;

