  signal reg_data_1         : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');
  signal reg_data_2_in      : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');
  signal imm_data           : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');
  signal alu_out_from_mem   : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');
  signal write_back_data_in : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');
  signal ccr_flags_in       : std_logic_vector(2 downto 0)                := (others => '0');
  signal in_port_data_in    : std_logic_vector(t_data_width - 1 downto 0) := (others => '0');

  -- signal outputs
  signal jmp_taken : std_logic;
  -- data outputs
  signal pc_out_plus_2     : std_logic_vector(t_data_width - 1 downto 0);
  signal alu_result        : std_logic_vector(t_data_width - 1 downto 0);
  signal reg_data_2_out    : std_logic_vector(t_data_width - 1 downto 0);
  signal ccr_flags_out     : std_logic_vector(2 downto 0);
  signal out_port_data_out : std_logic_vector(DATA_WIDTH - 1 downto 0);

begin

  execute_stage_inst : entity work.execute_stage
    port map (
      clk                  => clk,
      rst                  => rst,
      alu_op               => alu_op,
      jmp_type             => jmp_type,
      ccr_selector         => ccr_selector,
      ccr_enable           => ccr_enable,
      set_c                => set_c,
      is_branch            => is_branch,
      pc_in_plus_1         => pc_in_plus_1,
      reg_data_1           => reg_data_1,
      reg_data_2_in        => reg_data_2_in,
      imm_data             => imm_data,
      alu_out_from_mem     => alu_out_from_mem,
      write_back_data_in   => write_back_data_in,
      ccr_flags_in         => ccr_flags_in,
      mux_1_alu_src_select => mux_1_alu_src_select,
      mux_2_alu_src_select => mux_2_alu_src_select,
      jmp_taken            => jmp_taken,
      pc_out_plus_2        => pc_out_plus_2,
      alu_result           => alu_result,
      reg_data_2_out       => reg_data_2_out,
      ccr_flags_out        => ccr_flags_out,
      out_port_data_out    => out_port_data_out,
      in_port_data_in      => in_port_data_in
    );

  process is

    constant clk_period : time := 10 ns;

  begin

    -- Clock generation
    while true loop

      clk <= '0';
      wait for clk_period / 2;
      clk <= '1';
      wait for clk_period / 2;

    end loop;

  end process;

  p_stimulus : process is
  begin

    -- Reset the UUT
    rst <= '1';
    wait for 20 ns;
    rst <= '0';

    -- TEST CASE 1: Simple ALU ADD operation
    reg_data_1           <= x"00000005";                                                                                         -- 5
    reg_data_2_in        <= x"00000003";                                                                                         -- 3
    mux_1_alu_src_select <= "00";                                                                                                -- Select reg_data_1
    mux_2_alu_src_select <= "00";                                                                                                -- Select reg_data_2

    alu_op               <= ALU_ADD;                                                                                             -- ADD
    write_back_enable_in <= '1';
    wait for 100 ns;
    assert alu_result = x"00000008"
      report "Error: ALU ADD failed. Expected 00000008, got " & to_hstring(alu_result)
      severity error;
    report "ALU ADD test passed. Result: " & to_hstring(alu_result);

    -- TEST CASE 2 : IADD R1,5 operation
    reg_data_1           <= x"0000000A";                                                                                         -- R1 = 10
    imm_data             <= x"00000005";                                                                                         -- Immediate value = 5
    mux_1_alu_src_select <= "00";                                                                                                -- Select reg_data_1
    mux_2_alu_src_select <= "01";                                                                                                -- Select imm_data

    alu_op               <= ALU_ADD;                                                                                             -- ADD
    write_back_enable_in <= '1';
    wait for 100 ns;
    assert alu_result = x"0000000F"
      report "Error: IADD failed. Expected 0000000F, got " & to_hstring(alu_result)
      severity error;
    report "IADD test passed. Result: " & to_hstring(alu_result);

    report "--- TEST COMPLETED SUCCESSFULLY ---";

    -- TEST CASE 3 : TEST ZERO FLAG SETTING
    reg_data_1           <= x"00000005";                                                                                         -- R1 = 5
    reg_data_2_in        <= x"00000005";                                                                                         -- R2 = 5
    mux_1_alu_src_select <= "00";                                                                                                -- Select reg_data_1
    mux_2_alu_src_select <= "00";                                                                                                -- Select reg_data_2

    alu_op               <= ALU_SUB;                                                                                             -- SUB
    write_back_enable_in <= '1';
    ccr_enable           <= '1';
    ccr_selector         <= ccr_from_alu_flags;
    wait for 100 ns;
    assert ccr_flags_out(CCR_ZERO_BIT_POS) = '1'
      report "Error: ZERO flag not set correctly. Expected 1, got " & std_logic'image(ccr_flags_out(CCR_ZERO_BIT_POS))
      severity error;
    report "ZERO flag test passed. ZERO flag: " & std_logic'image(ccr_flags_out(CCR_ZERO_BIT_POS));

    -- TEST CASE 4 : SETC INSTRUCTION TEST
    reg_data_1           <= x"00000002";                                                                                         -- R1 = 2
    reg_data_2_in        <= x"00000003";                                                                                         -- R2 = 3
    mux_1_alu_src_select <= "00";                                                                                                -- Select reg_data_1
    mux_2_alu_src_select <= "00";                                                                                                -- Select reg_data_2
    alu_op               <= ALU_SUB;                                                                                             -- SUB
    write_back_enable_in <= '1';
    ccr_enable           <= '1';
    ccr_selector         <= ccr_from_set_c;
    set_c                <= '1';
    wait for 100 ns;
    assert ccr_flags_out(CCR_CARRY_BIT_POS) = '1'
      report "Error: CARRY flag not set correctly by SETC. Expected 1, got " & std_logic'image(ccr_flags_out(CCR_CARRY_BIT_POS))
      severity error;
    report "SETC instruction test passed. CARRY flag: " & std_logic'image(ccr_flags_out(CCR_CARRY_BIT_POS));

    -- TEST CASE 5 : JUMP TAKEN conditional TEST
    is_branch <= '1';
    jmp_type  <= jmp_jz;                                                                                                         -- Jump if Zero
    wait for 20 ns;
    assert jmp_taken = '1'
      report "Error: JUMP TAKEN failed. Expected 1, got " & std_logic'image(jmp_taken)
      severity error;
    report "JUMP TAKEN test passed. jmp_taken: " & std_logic'image(jmp_taken);

    -- TEST CASE 6 : PASS ALU OPERATION TEST
    reg_data_1           <= x"0000000A";                                                                                         -- R1 = 10
    reg_data_2_in        <= x"0000000B";                                                                                         -- R2 = 11
    mux_1_alu_src_select <= "00";                                                                                                -- Select reg_data_1
    mux_2_alu_src_select <= "00";                                                                                                -- Select reg_data_2
    alu_op               <= ALU_PAS;                                                                                             -- PASS
    write_back_enable_in <= '1';
    wait for 100 ns;
    assert alu_result = x"0000000A"
      report "Error: ALU PASS failed. Expected 0000000A, got " & to_hstring(alu_result)
      severity error;
    report "ALU PASS test passed. Result: " & to_hstring(alu_result);

    -- End of tests

    std.env.stop;
    wait;

  end process p_stimulus;

end architecture test;

