-- Testbenches have empty entities
end entity tb_alu;

architecture test of tb_alu is

  constant t_data_width : natural := DATA_WIDTH;
  -- 2. Signals to connect to UUT (Unit Under Test)
  signal src_a   : std_logic_vector(t_data_width - 1 downto 0);
  signal src_b   : std_logic_vector(t_data_width - 1 downto 0);
  signal alu_sel : std_logic_vector(2 downto 0);
  signal result  : std_logic_vector(t_data_width - 1 downto 0);
  signal flags   : std_logic_vector(2 downto 0);

begin

  -- 4. Instantiate the ALU
  uut_alu : entity work.alu
    generic map (
      data_width => T_DATA_WIDTH
    )
    port map (
      src_a   => src_a,
      src_b   => src_b,
      alu_sel => alu_sel,
      result  => result,
      flags   => flags

    );

  -- 5. Stimulus Process
  p_stimulus : process is
  begin

    report "--- STARTING ALU TEST ---";
    -- TEST CASE 1: ADD
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_add;                                                                    -- ADD
    wait for 10 ns;
    assert result = x"00000008"
      report "Error: ADD failed. Expected 00000008, got " & to_hstring(result)
      severity error;
    -- TEST CASE 2: SUB
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_sub;                                                                    -- SUB
    wait for 10 ns;
    assert result = x"00000002"
      report "Error: SUB failed. Expected 00000002, got " & to_hstring(result)
      severity error;
    -- TEST CASE 3: INC
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_inc;                                                                    -- INC
    wait for 10 ns;
    assert result = x"00000006"
      report "Error: INC failed. Expected 00000006, got " & to_hstring(result)
      severity error;
    -- TEST CASE 4: NOT
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_not;                                                                    -- NOT
    wait for 10 ns;
    assert result = x"FFFFFFFA"
      report "Error: NOT failed. Expected FFFFFFFA, got " & to_hstring(result)
      severity error;
    -- TEST CASE 5: AND
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_and;                                                                    -- AND
    wait for 10 ns;
    assert result = x"00000001"
      report "Error: AND failed. Expected 00000001, got " & to_hstring(result)
      severity error;
    -- TEST CASE 6: PASS A
    src_a   <= x"00000005";                                                              -- 5
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_pas_a;                                                                    -- PASS
    wait for 10 ns;
    assert result = x"00000005"
      report "Error: PASS failed. Expected 00000005, got " & to_hstring(result)
      severity error;
    -- TEST CASE 7: flags check for zero result
    src_a   <= x"00000003";                                                              -- 3
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_sub;                                                                    -- SUB
    wait for 10 ns;
    assert flags(0) = '1'
      report "Error: Zero flag failed. Expected 1, got " & std_logic'image(flags(0))
      severity error;
    -- TEST CASE 8: flags check for negative result
    src_a   <= x"00000002";                                                              -- 2
    src_b   <= x"00000003";                                                              -- 3
    alu_sel <= alu_sub;                                                                    -- SUB
    wait for 10 ns;
    assert flags(1) = '1'
      report "Error: Negative flag failed. Expected 1, got " & std_logic'image(flags(1))
      severity error;
    -- TEST CASE 9: flags check for carry out
    src_a   <= x"FFFFFFFF";                                                              -- Max unsigned
    src_b   <= x"00000001";                                                              -- 1
    alu_sel <= alu_add;                                                                    -- ADD
    wait for 10 ns;
    assert flags(2) = '1'
      report "Error: Carry flag failed. Expected 1, got " & std_logic'image(flags(2))
      severity error;
    report "--- ALU TEST COMPLETED SUCCESSFULLY ---";
    wait;

  end process p_stimulus;

end architecture test;
